# Ransomware File Integrity Monitor
import os
import hashlib
import time
from pathlib import Path
from collections import defaultdict

class RansomwareDetector:
    def __init__(self, watch_dirs, interval=5):
        self.watch_dirs = watch_dirs
        self.interval = interval
        self.baselines = {}
        self.alerts = []

    def compute_hash(self, filepath):
        sha256 = hashlib.sha256()
        try:
            with open(filepath, 'rb') as f:
                for chunk in iter(lambda: f.read(8192), b''):
                    sha256.update(chunk)
            return sha256.hexdigest()
        except (IOError, PermissionError):
            return None

    def snapshot(self):
        """Take a snapshot of all watched files."""
        state = defaultdict(dict)
        for watch_dir in self.watch_dirs:
            for root, dirs, files in os.walk(watch_dir):
                for fname in files:
                    fpath = os.path.join(root, fname)
                    h = self.compute_hash(fpath)
                    if h:
                        state[fpath]['hash'] = h
                        state[fpath]['mtime'] = os.path.getmtime(fpath)
                        state[fpath]['size'] = os.path.getsize(fpath)
        return dict(state)

    def detect_mass_modifications(self, current, threshold=50):
        """Detect mass file modifications typical of ransomware."""
        modified = []
        for fpath, info in current.items():
            if fpath in self.baselines:
                if self.baselines[fpath]['hash'] != info['hash']:
                    modified.append(fpath)

        if len(modified) > threshold:
            self.alerts.append({
                'type': 'MASS_MODIFICATION',
                'count': len(modified),
                'files': modified[:10],
                'time': time.time()
            })
            return True
        return False

    def detect_encryption_extensions(self, current):
        """Detect files renamed with ransomware extensions."""
        ransomware_exts = {'.encrypted', '.locked', '.crypto', '.crypt', '.enc'}
        renamed = []
        for fpath in current:
            ext = Path(fpath).suffix.lower()
            if ext in ransomware_exts and fpath not in self.baselines:
                renamed.append(fpath)
        if renamed:
            self.alerts.append({'type': 'ENCRYPTION_EXT', 'files': renamed})
        return renamed

    def monitor(self):
        """Main monitoring loop."""
        print("Taking initial snapshot...")
        self.baselines = self.snapshot()
        print(f"Baseline: {len(self.baselines)} files tracked")

        while True:
            time.sleep(self.interval)
            current = self.snapshot()
            self.detect_mass_modifications(current)
            self.detect_encryption_extensions(current)

            if self.alerts:
                latest = self.alerts[-1]
                print(f"ALERT: {latest['type']} - {len(latest.get('files', []))} files affected")
